code = """import json, re

# Load civic docs
with open(var_call_mE21EkZMD6kWWBeEVNBTfcmh, 'r', encoding='utf-8') as f:
    civic_docs = json.load(f)

results = []
for doc in civic_docs:
    text = doc.get('text','')
    lines = text.splitlines()
    for i, line in enumerate(lines):
        if re.search(r'begin construction', line, re.I) and re.search(r'spring', line, re.I):
            # collect previous up to 8 non-empty lines
            prev_lines = []
            j = i-1
            while j >= 0 and len(prev_lines) < 8:
                s = lines[j].strip()
                if s:
                    prev_lines.append(s)
                j -= 1
            prev_lines = prev_lines[::-1]
            # collect next up to 6 lines
            next_lines = []
            k = i
            while k < len(lines) and len(next_lines) < 6:
                s = lines[k].strip()
                if s:
                    next_lines.append(s)
                k += 1
            results.append({'filename': doc.get('filename',''), 'line_index': i, 'match_line': line.strip(), 'prev_lines': prev_lines, 'next_lines': next_lines})

print('__RESULT__:')
print(json.dumps(results))"""

